const https = require('https');
const fs = require('fs');
const path = require('path');

const coinId = '{{COIN_ID}}';
const currency = '{{CURRENCY}}';
const url = `https://api.coingecko.com/api/v3/simple/price?ids=${coinId}&vs_currencies=${currency}&include_24hr_change=true&include_market_cap=true`;

https.get(url, { headers: { 'User-Agent': 'Mozilla/5.0' } }, (res) => {
  let data = '';
  res.on('data', chunk => data += chunk);
  res.on('end', () => {
    try {
      const json = JSON.parse(data);
      if (!json[coinId]) {
        console.error('Coin not found:', coinId);
        process.exit(1);
      }
      const result = {
        coin: coinId,
        currency: currency,
        price: json[coinId][currency],
        market_cap: json[coinId][currency + '_market_cap'],
        change_24h: json[coinId][currency + '_24h_change'],
        timestamp: new Date().toISOString()
      };
      const outPath = path.join('{{WORKSPACE}}', '{{OUTPUT_FILE}}');
      fs.writeFileSync(outPath, JSON.stringify(result, null, 2));
      console.log('Crypto price:', result.coin, result.price, result.currency.toUpperCase());
      console.log('CREATED:', outPath);
    } catch (e) {
      console.error('Parse error:', e.message);
      process.exit(1);
    }
  });
}).on('error', e => { console.error(e.message); process.exit(1); });
